recommendations.helper_typescript:
export function statisticClaimSchema(props: {
  text: string;
  source: string;
  sourceAuthor: string;
  sourceDate: string;
  url: string;
  numericValue?: number;
  unit?: string;
}) {
  return {
    "@context": "https://schema.org",
    "@type": "CreativeWork",
    name: props.text,
    text: props.text,
    url: `${SITE_URL}${props.url}`,
    isBasedOn: {
      "@type": "CreativeWork",
      name: props.source,
      author: { "@type": "Organization", name: props.sourceAuthor },
      datePublished: props.sourceDate,
    },
    publisher: { "@type": "Organization", name: ORG_NAME, url: SITE_URL },
    ...(props.numericValue !== undefined
      ? {
          mainEntity: {
            "@type": "QuantitativeValue",
            value: props.numericValue,
            ...(props.unit ? { unitText: props.unit } : {}),
          },
        }
      : {}),
  };
}

